# -----------------------------------------------------------------------------
# Embedding
#
# Represents the vector representation of a document chunk.
#
# An embedding captures the semantic meaning of a chunk as a high-dimensional
# numerical vector. These vectors enable similarity-based retrieval by allowing
# mathematical comparisons instead of keyword matching.
#
# Fields:
# - chunk_id : Identifier of the source chunk.
# - vector   : Dense numerical representation generated by an embedding model.
#
# Design Notes:
# - Acts as the link between chunked text and semantic search.
# - Maintains a reference to its source chunk through chunk_id.
# - Designed as a lightweight data container using @dataclass.
# -----------------------------------------------------------------------------
from dataclasses import dataclass

@dataclass
class Embedding:
    chunk_id:str
    vector:list[float]